// Build an image generation prompt from the daily summary context.
// Returns the topic context extended with image_prompt and image_count.

const ctx = $input.first().json;
const summary = ctx.summary || {};
const topic_slug = ctx.topic_slug;
const date_key = ctx.date_key;

// Topic-specific visual style hints for stronger photorealistic thumbnails
const TOPIC_STYLE_HINTS = {
  finance:    'stock market floor, traders, financial charts on screens, Wall Street aesthetic, blue and gold palette',
  crypto:     'Bitcoin and Ethereum symbols, blockchain network visualization, neon blue on dark background, digital assets',
  economy:    'global economic map, GDP charts, world trade routes, clean data visualization, professional tone',
  health:     'modern medical research lab, DNA helix, clinical clean aesthetic, blue and white palette',
  ai:         'neural network nodes, glowing data streams, futuristic technology, electric blue and purple palette',
  energy:     'renewable energy landscape, solar panels and wind turbines, green technology, sunrise backdrop',
  technology: 'abstract circuit board, glowing tech interfaces, dark sleek aesthetic, neon accents',
};

const styleHint = TOPIC_STYLE_HINTS[topic_slug] || 'abstract data visualization, professional news aesthetic, clean modern design';
const headline = String(summary.headline || '').slice(0, 150);
const topicLabel = topic_slug.charAt(0).toUpperCase() + topic_slug.slice(1);

// Build a rich, specific prompt that avoids policy-violating content
const image_prompt = [
  `Professional ${topicLabel} news thumbnail.`,
  styleHint + '.',
  headline ? `Theme: ${headline}.` : '',
  'Cinematic lighting, photorealistic, high quality, no text overlays, no logos, no watermarks, no people.',
].filter(Boolean).join(' ');

// Request 1 image per daily run (cost-conscious default).
// Increase via AI_IMAGE_COUNT n8n variable if more images are needed.
const image_count = parseInt($vars.AI_IMAGE_COUNT || '1', 10) || 1;
const clamped_count = Math.min(4, Math.max(1, image_count));

// Provider and model selection.
// Falls back to openai for any unrecognised provider value.
const provider = ($vars.AI_PROVIDER || 'openai').toLowerCase();
const effective_provider = ['openai', 'google'].includes(provider) ? provider : 'openai';

// Model defaults mirror OPENAI_MODEL_DEFAULTS / GOOGLE_MODEL_DEFAULTS in openaiConfig.js.
const IMAGE_MODEL_DEFAULTS = {
  openai: $vars.OPENAI_MODEL_IMAGE_GENERATION || 'gpt-image-1',
  google: $vars.GOOGLE_MODEL_IMAGE_GENERATION || 'imagen-3.0-generate-001',
};
const image_model = IMAGE_MODEL_DEFAULTS[effective_provider];

return [{
  json: {
    ...ctx,
    _image_prompt: image_prompt,
    _image_count: clamped_count,
    _image_provider: effective_provider,
    _image_model: image_model,
  }
}];

