// Normalize Google Imagen API response to the shared image generation asset contract.
// Google returns: { predictions: [{ bytesBase64Encoded: '...', mimeType: 'image/png' }] }

const raw = $input.first().json;
const ctx = $('Build Image Prompt').first().json;
const ts = new Date().toISOString();

const predictions = raw?.predictions || [];
if (predictions.length === 0) {
  throw new Error(
    `Google Imagen returned no predictions for ${ctx.topic_slug}/${ctx.date_key}. ` +
    `Response: ${JSON.stringify(raw).slice(0, 300)}`
  );
}

const images = predictions.map((pred, i) => ({
  index: i,
  prompt: ctx._image_prompt,
  revised_prompt: null,
  provider: 'google',
  model: ctx._image_model,
  size: '1024x1024',
  format: 'b64_json',
  url: null,
  b64_json: pred.bytesBase64Encoded || null,
  mime_type: pred.mimeType || 'image/png',
  generated_at: ts,
}));

const image_assets = {
  images,
  image_count: images.length,
  provider: 'google',
  model: ctx._image_model,
  generated_at: ts,
};

// Strip internal underscore-prefixed keys from ctx before merging
const { _image_prompt, _image_count, _image_provider, _image_model, ...cleanCtx } = ctx;

return [{ json: { ...cleanCtx, image_assets } }];

// Normalize OpenAI images/generations response to the shared image generation asset contract.
// OpenAI returns: { created: ..., data: [{ url: '...', revised_prompt: '...' }] }

const raw = $input.first().json;
const ctx = $('Build Image Prompt').first().json;
const ts = new Date().toISOString();

const data = raw?.data || [];
if (data.length === 0) {
  throw new Error(
    `OpenAI images/generations returned no data for ${ctx.topic_slug}/${ctx.date_key}. ` +
    `Response: ${JSON.stringify(raw).slice(0, 300)}`
  );
}

const images = data.map((item, i) => ({
  index: i,
  prompt: ctx._image_prompt,
  revised_prompt: item.revised_prompt || null,
  provider: 'openai',
  model: ctx._image_model,
  size: '1024x1024',
  format: 'url',
  url: item.url || null,
  b64_json: null,
  mime_type: null,
  generated_at: ts,
}));

const image_assets = {
  images,
  image_count: images.length,
  provider: 'openai',
  model: ctx._image_model,
  generated_at: ts,
};

// Strip internal underscore-prefixed keys from ctx before merging
const { _image_prompt, _image_count, _image_provider, _image_model, ...cleanCtx } = ctx;

return [{ json: { ...cleanCtx, image_assets } }];

// Validate the normalized image generation asset against the shared contract.
// Non-blocking: logs a warning but does not throw, so a failed image step
// never blocks the rest of the daily editorial pipeline.

const VALID_PROVIDERS = ['openai', 'google'];
const VALID_FORMATS = ['url', 'b64_json'];

const ctx = $input.first().json;
const asset = ctx.image_assets;

const errors = [];

if (!asset || typeof asset !== 'object') {
  errors.push('image_assets is missing or not an object');
} else {
  if (!Array.isArray(asset.images) || asset.images.length === 0) {
    errors.push('image_assets.images must be a non-empty array');
  } else {
    asset.images.forEach((img, i) => {
      if (!img || typeof img !== 'object') { errors.push(`images[${i}] not an object`); return; }
      if (typeof img.index !== 'number') errors.push(`images[${i}].index missing`);
      if (!img.prompt || img.prompt.length < 10) errors.push(`images[${i}].prompt missing or too short`);
      if (!VALID_PROVIDERS.includes(img.provider)) errors.push(`images[${i}].provider invalid`);
      if (!img.model) errors.push(`images[${i}].model missing`);
      if (!VALID_FORMATS.includes(img.format)) errors.push(`images[${i}].format invalid`);
      if (img.format === 'url' && !img.url) errors.push(`images[${i}].url missing for url format`);
      if (img.format === 'b64_json' && !img.b64_json) errors.push(`images[${i}].b64_json missing for b64_json format`);
      if (!img.generated_at) errors.push(`images[${i}].generated_at missing`);
    });
  }
  if (typeof asset.image_count !== 'number') errors.push('image_assets.image_count missing');
  if (!VALID_PROVIDERS.includes(asset.provider)) errors.push('image_assets.provider invalid');
  if (!asset.model) errors.push('image_assets.model missing');
  if (!asset.generated_at) errors.push('image_assets.generated_at missing');
}

if (errors.length > 0) {
  // Non-blocking: attach errors as a warning field rather than throwing
  console.warn(
    `Image asset validation warnings for ${ctx.topic_slug}/${ctx.date_key} (${errors.length}):`,
    errors.join(', ')
  );
  return [{ json: { ...ctx, image_asset_warnings: errors } }];
}

return [{ json: { ...ctx, image_asset_warnings: null } }];
